class BankingViewModel extends ViewModel {
    private final MutableLiveData<BankingUiState> uiState = new MutableLiveData<>();
    private final TransactionProcessor transactionProcessor = new TransactionProcessor(new InMemoryAccountRepository());
    private final ExecutorService executor = Executors.newSingleThreadExecutor();

    public BankingViewModel() {
        uiState.setValue(new BankingUiState(
                transactionProcessor.getCurrentBalance(),
                false,
                "Ready"
        ));
    }

    LiveData<BankingUiState> getUiState() {
        return uiState;
    }

    void deposit(BigDecimal amount) {
        process(() -> transactionProcessor.deposit(amount));
    }

    void withdraw(BigDecimal amount) {
        process(() -> transactionProcessor.withdraw(amount));
    }

    void transfer(String targetAccountId, BigDecimal amount) {
        process(() -> transactionProcessor.transfer(targetAccountId, amount));
    }

    private void process(TransactionAction action) {
        BankingUiState current = safeState();
        uiState.postValue(new BankingUiState(current.balance, true, "Processing transaction..."));
        executor.execute(() -> {
            TransactionResult result = action.run();
            uiState.postValue(new BankingUiState(
                    transactionProcessor.getCurrentBalance(),
                    false,
                    result.message
            ));
        });
    }

    private BankingUiState safeState() {
        BankingUiState state = uiState.getValue();
        if (state == null) {
            return new BankingUiState(BigDecimal.ZERO.setScale(2, RoundingMode.HALF_EVEN), false, "Ready");
        }
        return state;
    }

    @Override
    protected void onCleared() {
        executor.shutdownNow();
        super.onCleared();
    }

    interface TransactionAction {
        TransactionResult run();
    }
}

