class TransactionProcessor {
    private final AccountRepository accountRepository;
    private final Object lock = new Object();
    private static final String CURRENT_ACCOUNT_ID = "PRIMARY_ACCOUNT";

    TransactionProcessor(AccountRepository accountRepository) {
        this.accountRepository = accountRepository;
        if (accountRepository.getBalance(CURRENT_ACCOUNT_ID) == null) {
            accountRepository.saveBalance(CURRENT_ACCOUNT_ID, new BigDecimal("1000.00"));
        }
    }

    BigDecimal getCurrentBalance() {
        synchronized (lock) {
            BigDecimal balance = accountRepository.getBalance(CURRENT_ACCOUNT_ID);
            return normalize(balance == null ? BigDecimal.ZERO : balance);
        }
    }

    TransactionResult deposit(BigDecimal amount) {
        synchronized (lock) {
            String validationError = validateAmount(amount);
            if (validationError != null) {
                return TransactionResult.failure(validationError);
            }

            BigDecimal current = getCurrentBalance();
            BigDecimal updated = normalize(current.add(amount));
            accountRepository.saveBalance(CURRENT_ACCOUNT_ID, updated);

            return TransactionResult.success("Deposit complete. Ref: " + generateTransactionId());
        }
    }

    TransactionResult withdraw(BigDecimal amount) {
        synchronized (lock) {
            String validationError = validateAmount(amount);
            if (validationError != null) {
                return TransactionResult.failure(validationError);
            }

            BigDecimal current = getCurrentBalance();
            if (current.compareTo(amount) < 0) {
                return TransactionResult.failure("Insufficient funds");
            }

            BigDecimal updated = normalize(current.subtract(amount));
            accountRepository.saveBalance(CURRENT_ACCOUNT_ID, updated);

            return TransactionResult.success("Withdrawal complete. Ref: " + generateTransactionId());
        }
    }

    TransactionResult transfer(String targetAccountId, BigDecimal amount) {
        synchronized (lock) {
            if (targetAccountId == null || targetAccountId.trim().isEmpty()) {
                return TransactionResult.failure("Target account is required");
            }

            String validationError = validateAmount(amount);
            if (validationError != null) {
                return TransactionResult.failure(validationError);
            }

            BigDecimal current = getCurrentBalance();
            if (current.compareTo(amount) < 0) {
                return TransactionResult.failure("Insufficient funds");
            }

            BigDecimal targetBalance = accountRepository.getBalance(targetAccountId);
            if (targetBalance == null) {
                targetBalance = BigDecimal.ZERO;
            }

            BigDecimal updatedSource = normalize(current.subtract(amount));
            BigDecimal updatedTarget = normalize(targetBalance.add(amount));

            accountRepository.saveBalance(CURRENT_ACCOUNT_ID, updatedSource);
            accountRepository.saveBalance(targetAccountId, updatedTarget);

            return TransactionResult.success("Transfer complete. Ref: " + generateTransactionId());
        }
    }

    private String validateAmount(BigDecimal amount) {
        if (amount == null) {
            return "Invalid amount";
        }
        if (amount.scale() > 2) {
            amount = amount.setScale(2, RoundingMode.HALF_EVEN);
        }
        if (amount.compareTo(BigDecimal.ZERO) <= 0) {
            return "Amount must be greater than zero";
        }
        return null;
    }

    private BigDecimal normalize(BigDecimal value) {
        return value.setScale(2, RoundingMode.HALF_EVEN);
    }

    private String generateTransactionId() {
        return UUID.randomUUID().toString();
    }
}

class TransactionResult {
    final boolean success;
    final String message;

    private TransactionResult(boolean success, String message) {
        this.success = success;
        this.message = message;
    }

    static TransactionResult success(String message) {
        return new TransactionResult(true, message);
    }

    static TransactionResult failure(String message) {
        return new TransactionResult(false, message);
    }
}

interface AccountRepository {
    BigDecimal getBalance(@NonNull String accountId);
    void saveBalance(@NonNull String accountId, @NonNull BigDecimal balance);
}

class InMemoryAccountRepository implements AccountRepository {
    private final java.util.Map<String, BigDecimal> balances = new java.util.concurrent.ConcurrentHashMap<>();

    @Override
    public BigDecimal getBalance(@NonNull String accountId) {
        return balances.get(accountId);
    }

    @Override
    public void saveBalance(@NonNull String accountId, @NonNull BigDecimal balance) {
        balances.put(accountId, balance);
    }
}

class MoneyFormatter {
    static String format(BigDecimal amount) {
        NumberFormat format = NumberFormat.getCurrencyInstance(Locale.getDefault());
        try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
                format.setCurrency(Currency.getInstance(Locale.getDefault()));
            }
        } catch (Exception ignored) {
        }
        return format.format(amount);
    }
}